def seed():
    create_tables()
    db = SessionLocal()
    
    # Disable foreign keys for seeding to prevent circular reference errors (SQLite only)
    try:
        from sqlalchemy import text
        if db.bind.dialect.name == "sqlite":
            db.execute(text("PRAGMA foreign_keys = OFF;"))
    except Exception:
        pass

    # Clean existing data to allow safe rerun / refresh
    print("Cleaning existing database data...")
    for model_name, model_cls in reversed([
        ("RolesMaster", RolesMaster),
        ("StageActivityMaster", StageActivityMaster),
        ("StageMaster", StageMaster),
        ("User", User),
        ("Client", Client),
        ("Project", Project),
        ("ChapterInfo", ChapterInfo),
        ("File", File),
        ("FileVersion", FileVersion),
        ("ProjectStylesheet", ProjectStylesheet),
        ("StageDetail", StageDetail),
        ("WorkflowMaster", WorkflowMaster),
    ]):
        try:
            db.query(model_cls).delete()
            db.commit()
        except Exception as e:
            db.rollback()
            print(f"Error cleaning {model_name}: {e}")

    # Insert dumped data
    print("Seeding database...")
    for model_name, model_cls in [
        ("RolesMaster", RolesMaster),
        ("StageActivityMaster", StageActivityMaster),
        ("StageMaster", StageMaster),
        ("User", User),
        ("Client", Client),
        ("Project", Project),
        ("ChapterInfo", ChapterInfo),
        ("File", File),
        ("FileVersion", FileVersion),
        ("ProjectStylesheet", ProjectStylesheet),
        ("StageDetail", StageDetail),
        ("WorkflowMaster", WorkflowMaster),
    ]:
        rows = DUMPED_DATA.get(model_name, [])
        inserted = 0
        # Collect seeded chapter IDs to validate File.chapter_id foreign keys
        seeded_chapter_ids = {c['id'] for c in DUMPED_DATA.get('ChapterInfo', [])}
        for row in rows:
            if model_name == "User" and "password" in row:
                from app.domains.auth.security import hash_password
                row_copy = row.copy()
                row_copy["password_hash"] = hash_password(row_copy["password"])
                del row_copy["password"]
                instance = model_cls(**row_copy)
            elif model_name == "File":
                row_copy = row.copy()
                if row_copy.get("chapter_id") not in seeded_chapter_ids:
                    row_copy["chapter_id"] = None
                instance = model_cls(**row_copy)
            else:
                instance = model_cls(**row)
            db.add(instance)
            inserted += 1
        try:
            db.commit()
            print(f"  OK    Seeded {inserted} rows for {model_name}")
        except Exception as e:
            db.rollback()
            print(f"  ERROR Seeding {model_name}: {e}")

    # Re-enable foreign keys (SQLite only)
    try:
        from sqlalchemy import text
        if db.bind.dialect.name == "sqlite":
            db.execute(text("PRAGMA foreign_keys = ON;"))
    except Exception:
        pass

    # Reset primary key sequences for PostgreSQL to avoid duplicate key errors on future inserts
    try:
        if db.bind.dialect.name == "postgresql":
            from sqlalchemy import text
            print("Syncing PostgreSQL primary key sequences...")
            tables_to_sync = [
                ("users", "id"),
                ("clients", "id"),
                ("projects", "id"),
                ("project_stylesheets", "id"),
                ("roles_master", "id"),
                ("stage_activity_master", "id"),
                ("stage_master", "id"),
                ("stages_details", "id"),
                ("workflow_master", "id"),
                ("chapter_details", "id")
            ]
            for table, pk in tables_to_sync:
                db.execute(text(f"SELECT setval(pg_get_serial_sequence('{table}', '{pk}'), COALESCE(MAX({pk}), 1)) FROM {table};"))
            db.commit()
            print("PostgreSQL sequences synced successfully!")
    except Exception as e:
        db.rollback()
        print(f"Error syncing PostgreSQL sequences: {e}")
    
    db.close()
    print("Database seeding completed successfully!")

if __name__ == "__main__":
    seed()
